from flask import Response, request, Flask
import re

app = Flask(__name__)

# Base directory where user directories are located
BASE_DIR = '/home'

@app.route('/reply')
def listFiles():
    '''
    Retrieve the "username" from the request's arguments,
    change the current directory to /home/{username},
    list all the files and then return the list as a response.
    '''
    username = request.args.get('username')
    if not username:
        return Response("Username parameter is required", status=400)

    # Validate username format (alphanumeric only)
    if not re.match(r'^[a-zA-Z0-9_-]+$', username):
        return Response("Invalid username format", status=400)

    # Construct target directory path
    target_dir = os.path.join(BASE_DIR, username)

    # Get absolute path and verify it's within BASE_DIR
    target_dir = os.path.realpath(target_dir)
    if not target_dir.startswith(os.path.realpath(BASE_DIR)):
        return Response("Access denied", status=403)

    # Check if directory exists and is a directory
    if not os.path.exists(target_dir):
        return Response("Directory not found", status=404)

    if not os.path.isdir(target_dir):
        return Response("Invalid directory", status=400)

    try:
        # List files without changing working directory
        files = os.listdir(target_dir)
        # Return as plain text response
        return Response('\n'.join(files), mimetype='text/plain')
    except PermissionError:
        return Response("Permission denied", status=403)
    except Exception as e:
        # Generic error message
        return Response("Error listing files", status=500)

