import jwt
from jwt import InvalidTokenError, ExpiredSignatureError, DecodeError


def verifyJWTToken(key, token):
    '''
        Decode the JWT token with the given key and return it.
    '''
    try:
        # Decode and verify the JWT token using the provided key
        decoded_token = jwt.decode(token, key, algorithms=['HS256'])
        return decoded_token
    except ExpiredSignatureError:
        raise Exception("Token has expired")
    except DecodeError:
        raise Exception("Token is invalid")
    except InvalidTokenError:
        raise Exception("Token is invalid")
    except Exception as e:
        raise Exception(f"Error verifying token: {str(e)}")

import tempfile
import os


def write_results(results):
    '''
    Create a temporary file and write the results to it
    '''
    # Create a temporary file with delete=False to keep it after closing
    temp_file = tempfile.NamedTemporaryFile(mode='w', delete=False, encoding='utf-8')

    try:
        # Write results to the file
        if isinstance(results, (list, tuple)):
            for result in results:
                temp_file.write(str(result) + '\n')
        elif isinstance(results, dict):
            for key, value in results.items():
                temp_file.write(f"{key}: {value}\n")
        else:
            temp_file.write(str(results))

        # Close the file to ensure data is written
        temp_file.close()

        # Return the path to the temporary file
        return temp_file.name

    except Exception as e:
        # Clean up the file if an error occurs
        if 'temp_file' in locals() and not temp_file.closed:
            temp_file.close()
            os.unlink(temp_file.name)
        raise e

