import json

class Payload(object):
    def to_dict(self):
        # Convert the object to a dictionary for JSON serialization
        return {"type": "Payload", "data": "example"}

    @classmethod
    def from_dict(cls, data):
        # Reconstruct the object from a dictionary
        if data.get("type") == "Payload":
            return cls()
        raise ValueError("Invalid data for Payload")

def makeSerializedData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it to JSON before returning it
    '''
    return json.dumps(payload.to_dict())

# Example usage
