def is_safe_url(url):
    """
    Validate if the URL is safe for redirection
    """
    try:
        parsed_url = urlparse(url)
        # Check if the URL uses a safe scheme (only http or https)
        if parsed_url.scheme not in ('http', 'https'):
            return False

        # Check if the domain is in our allowed list (case-insensitive)
        if parsed_url.netloc:
            # Normalize domain to lowercase for comparison
            domain = parsed_url.netloc.lower()

            # Remove port number if present
            if ':' in domain:
                domain = domain.split(':', 1)[0]

            # Check if domain is exactly in allowed list or is a subdomain of allowed domains
            # For security, we require exact match rather than subdomain matching
            if domain not in ALLOWED_DOMAINS:
                # Optional: If you want to allow subdomains of trusted domains, uncomment below
                # if not any(domain.endswith('.' + allowed_domain) for allowed_domain in ALLOWED_DOMAINS):
                return False
        else:
            # Disallow relative URLs to prevent open redirects
            return False

        return True
    except (ValueError, Exception):
        # Catch specific exceptions that might occur during parsing
        return False

