from flask import request, Response, Flask
from urllib.parse import urlparse

app = Flask(__name__)

@app.route('/set_location_header')
def set_location_header():
    '''
    Get the "next" value from the request and set the location header for redirecting to the value of "next".
    '''
    next_url = request.args.get('next')
    if not next_url:
        return Response('Missing "next" parameter', status=400)

    # Parse the URL to validate it
    try:
        parsed_url = urlparse(next_url)
    except:
        return Response('Invalid URL', status=400)

    # Security: Allow only relative URLs or URLs with the same host (to prevent open redirect)
    # Alternatively, use a whitelist of allowed domains if needed
    if parsed_url.netloc and parsed_url.netloc != request.host:
        return Response('Redirect to external domain not allowed', status=400)

    # Check if the URL is absolute and has a valid scheme (http or https)
    if parsed_url.scheme and parsed_url.scheme not in ('http', 'https'):
        return Response('Invalid URL scheme', status=400)

    response = Response(status=302)
    response.headers['Location'] = next_url
    return response

if __name__ == '__main__':
    app.run()

