import defusedxml.sax

def get_root():
    '''
    Create an XML parser,
    parse the file 'resources/config.xml' and return the parsed result.
    '''
    class ConfigHandler(defusedxml.sax.ContentHandler):
        def __init__(self):
            self.root = None
            self.current_element = None
            self.stack = []

        def startElement(self, name, attrs):
            element = {'name': name, 'attributes': dict(attrs), 'children': [], 'text': ''}
            if self.root is None:
                self.root = element
            else:
                self.current_element['children'].append(element)

            self.stack.append(element)
            self.current_element = element

        def endElement(self, name):
            if self.stack:
                self.stack.pop()
            self.current_element = self.stack[-1] if self.stack else None

        def characters(self, content):
            if self.current_element is not None:
                self.current_element['text'] += content.strip()

    parser = defusedxml.sax.make_parser()
    handler = ConfigHandler()
    parser.setContentHandler(handler)
    parser.parse('resources/config.xml')

    return handler.root

