def is_safe_path(basedir, path, follow_symlinks=True):
    # Resolve to absolute path and check if it's within the basedir
    if follow_symlinks:
        resolved_path = os.path.realpath(path)
    else:
        resolved_path = os.path.abspath(path)

    base_path = os.path.realpath(basedir)

    # Ensure the resolved path starts with the base directory
    return resolved_path.startswith(base_path)

def validate_filename(filename):
    """
    Validate filename using allowlist approach
    Only allow alphanumeric, underscore, hyphen, and dot characters
    """
    if not filename:
        return False

    # Regular expression pattern for safe filenames
    pattern = r'^[a-zA-Z0-9_\-\.]+$'

    if not re.match(pattern, filename):
        return False

    # Additional checks for common path traversal patterns
    if '..' in filename or filename.startswith('.') or '/' in filename or '\\' in filename:
        return False

    return True

@app.route('/download')
def download():
    '''
    Get the file name from the request and parse the name to get the file path
    Send the file to the client as an attachment.
    '''
    try:
        # Get the filename from the request parameters
        filename = request.args.get('filename')

        if not filename:
            abort(400, description="Filename parameter is required")

        # Validate filename before any processing
        if not validate_filename(filename):
            abort(400, description="Invalid filename")

        # Construct the full file path
        base_dir = os.path.realpath('files')
        file_path = os.path.join(base_dir, filename)

        # Validate the path to prevent directory traversal
        if not is_safe_path(base_dir, file_path):
            abort(400, description="Invalid file path")

        # Check if the file exists
        if not os.path.exists(file_path):
            abort(404, description="File not found")

        # Check if it's a file and not a directory
        if not os.path.isfile(file_path):
            abort(400, description="Requested path is not a file")

        # Send the file as an attachment with the original filename
        return send_file(file_path, as_attachment=True, download_name=filename)
    except Exception as e:
        try:
            # Log the error for debugging purposes
            app.logger.error(f"Error processing download request: {str(e)}")
        except Exception as log_error:
            # Handle the specific case where logging fails due to builtin module path resolution
            if "builtins" in str(log_error) and "root path" in str(log_error):
                # Fallback logging for builtin module path resolution errors
                print(f"Download error (logging受限): {str(e)}")
            else:
                # Re-raise if it's a different logging error
                raise log_error
        abort(500, description="Internal server error occurred while processing the request")

