from lxml import etree
from io import StringIO

from django.http import HttpResponse


def xpath_query(request):
    '''
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    '''
    xpath_value = request.GET.get('xpath')
    xml_payload = request.GET.get('xml')

    if not xpath_value or not xml_payload:
        return HttpResponse("Missing required parameters: 'xpath' or 'xml'", status=400)

    try:
        parser = etree.XMLParser(resolve_entities=False)
        xml_tree = etree.parse(StringIO(xml_payload), parser)
    except etree.XMLSyntaxError:
        return HttpResponse("Invalid XML format", status=400)

    try:
        query = f"/tag[@id='{xpath_value}']"
        result = xml_tree.xpath(query)
    except etree.XPathError:
        return HttpResponse("Invalid XPath query", status=400)

    if not result:
        return HttpResponse("No results found", status=404)

    result_strings = []
    for element in result:
        if hasattr(element, 'text') and element.text:
            result_strings.append(element.text)
        else:
            result_strings.append(etree.tostring(element, encoding='unicode'))

    return HttpResponse("\n".join(result_strings))

