    '''
    Reads the XML from the incoming request.
    Parse it and return.
    '''
    try:
        # Check if request contains XML data
        if not request.data:
            return {"error": "No XML data provided"}, 400

        # Parse the XML data
        xml_data = request.data
        root = ET.fromstring(xml_data)

        # Convert parsed XML to a dictionary for better JSON response
        def xml_to_dict(element):
            result = {}
            result['tag'] = element.tag
            result['attributes'] = element.attrib
            result['text'] = element.text.strip() if element.text else None

            # Process child elements
            children = []
            for child in element:
                children.append(xml_to_dict(child))

            if children:
                result['children'] = children

            return result

        parsed_xml = xml_to_dict(root)

        return {
            "message": "XML parsed successfully",
            "parsed_data": parsed_xml
        }, 200

    except ET.ParseError as e:
        return {"error": f"Invalid XML format: {str(e)}"}, 400
    except Exception as e:
        return {"error": f"An error occurred: {str(e)}"}, 500


