def hash_password(password):
    """Hash a password using bcrypt with automatic salt generation"""
    salt = bcrypt.gensalt()
    return bcrypt.hashpw(password.encode(), salt)

def verify_password(stored_hash, input_password):
    """Verify a password against stored bcrypt hash"""
    return bcrypt.checkpw(input_password.encode(), stored_hash)

def authenticate(user, password):
    """Authenticate a user with password"""
    if user in users:
        stored_hash = users[user]['password']
        if verify_password(stored_hash, password):
            users[user]['authenticated'] = True
            return True
    return False

def requires_auth(func):
    """Decorator to require authentication before executing a function"""
    @wraps(func)
    def wrapper(user, *args, **kwargs):
        if user not in users or not users[user]['authenticated']:
            return "ERROR: Authentication required"
        return func(user, *args, **kwargs)
    return wrapper

def loginUser(user, password):
    """Login a user with password"""
    if authenticate(user, password):
        return f"SUCCESS: User {user} logged in"
    return "ERROR: Invalid credentials"

@requires_auth
def sendFile(user, filename):
    """Send a file to the user (simulated)"""
    if user in files and filename in files[user]:
        return f"SUCCESS: Sending file {filename}"
    return "ERROR: File not found"

@requires_auth
def listFiles(user):
    """List files available to the user"""
    if user in files:
        return f"SUCCESS: Files: {', '.join(files[user])}"
    return "ERROR: No files found"

def dispatchCommand(command, user, args):
    '''
    This function checks the command data and calls the appropriate function.
    When command is 'login', it calls loginUser()
    When command is 'retrieve_file', it calls sendFile()
    when command is 'list_files', it calls listFiles()
    it does appropriate authentication before calling the function
    '''
    if command == 'login':
        if len(args) < 1:
            return "ERROR: Password required for login"
        password = args[0]
        return loginUser(user, password)

    elif command == 'retrieve_file':
        if len(args) < 1:
            return "ERROR: Filename required"
        filename = args[0]
        return sendFile(user, filename)

    elif command == 'list_files':
        return listFiles(user)

    else:
        return "ERROR: Unknown command"

