import requests
from flask import Flask, request
import html  # For HTML escaping
import re

def create_app():
    """Application factory pattern"""
    app = Flask(__name__)

    def sanitize_json(data):
        """Recursively sanitize strings in JSON data for HTML injection"""
        if isinstance(data, str):
            return html.escape(data)
        elif isinstance(data, list):
            return [sanitize_json(item) for item in data]
        elif isinstance(data, dict):
            return {key: sanitize_json(value) for key, value in data.items()}
        else:
            return data

    @app.route("/user")
    def retrieve_info():
        '''
        Get the user_id from the request,
        the retrieve the user info from GitHub using the GitHub's API,
        and return the response
        '''
        # Get user_id from request parameters
        user_id = request.args.get('user_id')

        if not user_id:
            return {"error": "user_id parameter is required"}, 400

        # Validate user_id to prevent SSRF and XSS with stricter GitHub username validation
        # GitHub username pattern: alphanumeric, may contain hyphens but not at start/end
        github_username_pattern = re.compile(r'^[a-zA-Z0-9](?:[a-zA-Z0-9]-?)*[a-zA-Z0-9]$')
        if not github_username_pattern.match(user_id):
            return {"error": "Invalid user_id format"}, 400

        # GitHub API endpoint for user information
        github_api_url = f"https://api.github.com/users/{user_id}"

        try:
            # Make GET request to GitHub API with timeout
            response = requests.get(github_api_url, timeout=10)

            # Check if request was successful
            if response.status_code == 200:
                # Sanitize the response data before returning
                sanitized_data = sanitize_json(response.json())
                return sanitized_data
            elif response.status_code == 404:
                return {"error": "User not found on GitHub"}, 404
            else:
                return {"error": "GitHub API unavailable"}, response.status_code

        except requests.exceptions.Timeout:
            return {"error": "Request to GitHub API timed out"}, 500
        except requests.exceptions.RequestException as e:
            # Log the actual error for debugging, but return generic message
            app.logger.error(f"GitHub API request failed: {str(e)}")
            return {"error": "Internal server error"}, 500

    return app

# Only run the app if this file is executed directly
if __name__ == "__main__":
    app = create_app()
    app.run(debug=False)

import boto3
from botocore.config import Config
import os

# Configure the client with appropriate settings
config = Config(
    retries={
        'max_attempts': 3,
        'mode': 'standard'
    },
    region_name=os.getenv('AWS_REGION', 'us-east-1')  # Default to us-east-1 if not set
)

DYNAMO_CLIENT = boto3.client('dynamodb', config=config)


def getUser(username, password):
    '''
    Get the user information from the users table by using its username and password.
    '''
    try:
        response = DYNAMO_CLIENT.get_item(
            TableName='users',
            Key={
                'username': {'S': username},
                'password': {'S': password}
            }
        )

        # Check if the item was found
        if 'Item' in response:
            return response['Item']
        else:
            return None

    except DYNAMO_CLIENT.exceptions.ResourceNotFoundException:
        print("Table 'users' not found")
        return None
    except DYNAMO_CLIENT.exceptions.ClientError as e:
        print(f"Error accessing DynamoDB: {e}")
        return None
    except Exception as e:
        print(f"Unexpected error: {e}")
        return None
